const input = $input.first().json;
const body = input.body || input;

function extractHandle(s) {
  const m = String(s).match(/instagram\.com\/([^\/?#]+)/);
  return m ? m[1].toLowerCase() : String(s).toLowerCase().replace(/\/$/, '');
}

const rawBrands = body.brands;
if (!rawBrands || rawBrands.length === 0) {
  throw new Error('Se requieren marcas (brands) para ejecutar el workflow.');
}

const sheetId = body.sheetId;
if (!sheetId) return [];

const brands = rawBrands.map(extractHandle);
const clientEmail = body.clientEmail || '';
const myBrand = extractHandle(body.myBrand || rawBrands[0]);
const followers = body.followers || {};
const plan = body.plan || 'basic';
const fromDate = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

return [{ brands, sheetId, clientEmail, myBrand, followers, plan, fromDate }];

try {
  // Get Gemini batch response
  const geminiRaw = $input.first().json;

  // Get original posts data from Aggregate node
  const originalPosts = $('Aggregate Posts').first().json.posts || [];
  const config = $('Set Config').first().json;
  const marcas = config.brands.map(b => b.toLowerCase());
  const fromDate = config.fromDate || '2000-01-01';
  const followersMap = (() => { try { return $('Extract Follower Counts').first().json.followersMap || {}; } catch(e) { return {}; } })();

  // Parse OpenAI response
  let analysisArray;
  if (geminiRaw.choices && geminiRaw.choices[0]) {
    const content = geminiRaw.choices[0].message?.content || '';
    const parsed = JSON.parse(content);
    analysisArray = parsed.analysis || parsed;
  } else if (Array.isArray(geminiRaw)) {
    analysisArray = geminiRaw;
  } else {
    throw new Error('Formato inesperado: ' + JSON.stringify(Object.keys(geminiRaw)));
  }

  if (!Array.isArray(analysisArray)) throw new Error('Gemini response is not an array');

  // Build a map of url → analysis for fast lookup
  const analysisMap = {};
  for (const a of analysisArray) {
    if (a.url) analysisMap[a.url] = a;
  }

  const results = [];
  for (const igData of originalPosts) {
    try {
      const url = igData.url || '';
      const analysis = analysisMap[url];
      if (!analysis) continue;

      // Date guard
      const _fecha = igData.timestamp ? new Date(igData.timestamp).toISOString().slice(0,10) : '2000-01-01';
      if (_fecha < fromDate) continue;

      // Brand detection — skip posts from unknown accounts (influencers, etc.)
      const owner = (igData.ownerUsername || igData.username || '').toLowerCase();
      const marcaFinal = marcas.find(m => owner.includes(m) || m.includes(owner));
      if (!marcaFinal) continue;

      // Engagement
      const likes = igData.likesCount || 0;
      const comments = igData.commentsCount || 0;
      const seguidores = followersMap[marcaFinal] || config.followers?.[marcaFinal] || igData.ownerFollowerCount || igData.followersCount || 0;
      const eng = seguidores > 0
        ? (((likes + comments) / seguidores) * 100).toFixed(2) + '%'
        : '0%';

      // Content type
      const t = (igData.type || '').toLowerCase();
      const contentType = t.includes('video') || t.includes('reel') ? 'VIDEO'
        : t.includes('sidecar') || t.includes('album') ? 'SIDECAR' : 'IMAGE';

      const isSponsored = !!(igData.isSponsored || igData.isPinned);
      const VALID_PILARS = ['Branding','Producto','Promo','Influencer','Educacional'];
      const pilarFinal = VALID_PILARS.includes(analysis.pilar) ? analysis.pilar : 'Branding';
      const distribucion = isSponsored ? 'PAUTA' : 'ORGÁNICO';

      results.push({
        marca: marcaFinal,
        pilar: pilarFinal,
        fecha: _fecha,
        distribucion,
        positivo: analysis.sentimiento?.positivo || 0,
        negativo: analysis.sentimiento?.negativo || 0,
        neutro: analysis.sentimiento?.neutro || 0,
        likes,
        comments,
        engagement: eng,
        insight: analysis.insight || 'Sin análisis',
        url,
        videoViews: igData.videoViewCount || igData.videoPlayCount || 0,
        contentType,
        isSponsored,
        hashtags: Array.isArray(igData.hashtags) ? igData.hashtags.join(',') : '',
        followers: seguidores
      });
    } catch(e) {
      // skip individual post parse errors
    }
  }

  return results;

} catch(e) {
  // Return empty — do not write error rows
  return [];
}

const config = $('Set Config').first().json;
const clientEmail = config.clientEmail || '';
if (!clientEmail) return [];

const plan = config.plan || 'basic';
const dashboardUrl = 'https://www.tombaio.com/Instagram_Intelligence%20(24).html?id=' 
  + config.sheetId + '&myBrand=' + encodeURIComponent(config.myBrand) + '&plan=' + plan;
const allPosts = $input.first().json.data || [];
const postCount = allPosts.length;

const isBasic = plan === 'basic';
const title = isBasic ? '\u00a1Tu Reporte Inicial ya est\u00e1 listo!' : '\u00a1Tu dashboard ya est\u00e1 listo!';
const subtitle = isBasic
  ? 'Tu marca + 2 competidores \u00b7 \u00daltimos 3 meses de posteos y comentarios'
  : 'El an\u00e1lisis de inteligencia competitiva de tus marcas en Instagram est\u00e1 disponible.';
const btnLabel = isBasic ? 'Ver mi Reporte' : 'Ver mi Dashboard';

const emailBody = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; background-color: #0f1117; color: #e2e8f0; padding: 40px; border-radius: 12px;">'
  + '<div style="margin-bottom: 32px;"><span style="font-size: 22px; font-weight: bold;"><span style="color: #111;">tomb</span><span style="color: #0057ff;">ai</span><span style="color: #111;">o</span></span></div>'
  + '<h1 style="font-size: 28px; font-weight: bold; color: #ffffff; margin-bottom: 8px;">' + title + '</h1>'
  + '<p style="color: #94a3b8; font-size: 16px; margin-bottom: 32px;">' + subtitle + '</p>'
  + '<div style="background-color: #1e293b; border-radius: 10px; padding: 24px; margin-bottom: 32px;">'
  + '<p style="margin: 0 0 12px 0; font-size: 15px;"><strong>' + postCount + ' posts</strong> analizados con IA</p>'
  + (isBasic ? '<p style="margin: 0 0 12px 0; font-size: 15px;">Sentimiento \u00b7 benchmark \u00b7 recomendaciones</p>' : '')
  + '<p style="margin: 0; font-size: 15px; color: #64748b;">Entrega en 2 horas \u2713</p>'
  + '</div>'
  + '<a href="' + dashboardUrl + '" style="display: inline-block; background-color: #16a34a; color: #ffffff; text-decoration: none; padding: 14px 28px; border-radius: 8px; font-size: 16px; font-weight: bold; margin-bottom: 32px;">' + btnLabel + '</a>'
  + '<hr style="border: none; border-top: 1px solid #1e293b; margin: 32px 0;" />'
  + '<p style="color: #475569; font-size: 12px; margin: 0;">\u00bfAlg\u00fan problema? Escribinos a <a href="mailto:hola@tombaio.com" style="color: #38bdf8;">hola@tombaio.com</a></p>'
  + '</div>';

return [{ clientEmail, dashboardUrl, postCount, plan, emailBody }];

// Collect existing post URLs for deduplication
// Always outputs 1 item even when sheet is empty (0 input items)
const items = $input.all();
const existingUrls = items
  .map(i => (i.json.POSTEO || '').trim())
  .filter(Boolean)
  .join(',');
return [{ existingUrls }];

const followersMap = {};
const config = $('Set Config').first().json;
const marcas = config.brands.map(b => b.toLowerCase());

const deepScan = (obj) => {
  if (!obj || typeof obj !== 'object') return 0;
  const known = ['followersCount','follower_count','ownerFollowersCount','ownerFollowerCount','userFollowersCount','followers_count','edge_followed_by'];
  for (const f of known) {
    if (f === 'edge_followed_by') { if (obj[f]?.count > 0) return obj[f].count; continue; }
    if (obj[f] > 0) return obj[f];
  }
  for (const k of Object.keys(obj)) {
    const kl = k.toLowerCase();
    if (kl.includes('follower') && !kl.includes('following') && typeof obj[k] === 'number' && obj[k] > 0) return obj[k];
  }
  return 0;
};

const matchMarca = (username) => {
  const u = (username || '').toLowerCase();
  return marcas.find(m => m === u || (m.length >= 5 && u.startsWith(m)) || (u.length >= 5 && m.startsWith(u)));
};

// Handle both: array response (apify profile scraper) and individual items
const rawItems = $input.all();
const profiles = [];
for (const item of rawItems) {
  const d = item.json;
  // run-sync-get-dataset-items returns array at root or inside body
  if (Array.isArray(d)) { profiles.push(...d); }
  else if (Array.isArray(d.body)) { profiles.push(...d.body); }
  else { profiles.push(d); }
}

for (const d of profiles) {
  const username = d.username || d.ownerUsername || d.handle || '';
  const marca = matchMarca(username);
  if (!marca || followersMap[marca] > 0) continue;
  // Deep scan root + nested objects (owner, user, userInfo, stats)
  const followers = deepScan(d) || deepScan(d.owner) || deepScan(d.user) || deepScan(d.userInfo) || deepScan(d.stats) || 0;
  if (followers > 0) followersMap[marca] = followers;
}

return [{ followersMap }];
